//! Spec-compliance tests: Numbering Behavior (ISO 29500-1 §17.9)
//!
//! These tests verify our implementation against specific OOXML numbering
//! constructs defined in the spec. Tests that fail document real gaps —
//! they encode the *correct* spec behavior.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, TrackedBlock};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/numbering-spec";

// ── helpers ──────────────────────────────────────────────────────────────

/// Collect all paragraphs from a canonical document's top-level blocks.
fn all_paragraphs(doc: &CanonDoc) -> Vec<&stemma::ParagraphNode> {
    let mut paras = Vec::new();
    collect_paragraphs_tracked(&doc.blocks, &mut paras);
    paras
}

fn collect_paragraphs_tracked<'a>(
    blocks: &'a [TrackedBlock],
    out: &mut Vec<&'a stemma::ParagraphNode>,
) {
    for tracked in blocks {
        match &tracked.block {
            BlockNode::Paragraph(p) => out.push(p),
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_paragraphs_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

fn collect_paragraphs_bare<'a>(blocks: &'a [BlockNode], out: &mut Vec<&'a stemma::ParagraphNode>) {
    for block in blocks {
        match block {
            BlockNode::Paragraph(p) => out.push(p),
            BlockNode::Table(t) => {
                for row in &t.rows {
                    for cell in &row.cells {
                        collect_paragraphs_bare(&cell.blocks, out);
                    }
                }
            }
            BlockNode::OpaqueBlock(_) => {}
        }
    }
}

/// Get paragraphs that have numbering info (auto-numbered).
fn numbered_paragraphs(doc: &CanonDoc) -> Vec<&stemma::ParagraphNode> {
    all_paragraphs(doc)
        .into_iter()
        .filter(|p| p.numbering.is_some())
        .collect()
}

// ── suff="nothing" (§17.9.28) ──────────────────────────────────────────

/// ISO 29500-1 §17.9.28: When suff val="nothing", there shall be no content
/// between the numbering text and the paragraph body — no tab, no space.
///
/// The fixture has two numbering definitions:
///   numId=1: suff="nothing" (no separator)
///   numId=2: suff omitted (defaults to "tab")
///
/// We test that:
///   1. The synthesized_text is correct for both ("1.", "2.")
///   2. The rendered_text for suff="nothing" has NO separator between prefix and body
///   3. The rendered_text for default suff has a tab separator
#[test]
fn spec_suff_nothing_no_separator() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "suff-nothing");
    let paras = numbered_paragraphs(&doc);

    assert!(
        paras.len() >= 4,
        "expected at least 4 numbered paragraphs, got {}",
        paras.len()
    );

    // First two paragraphs use suff="nothing" (numId=1)
    let p0 = paras[0];
    let p1 = paras[1];

    let n0 = p0.numbering.as_ref().expect("P0 should have numbering");
    assert_eq!(
        n0.synthesized_text, "1.",
        "P0 synthesized text should be '1.'"
    );
    assert_eq!(n0.num_id, 1, "P0 should use numId=1");

    let n1 = p1.numbering.as_ref().expect("P1 should have numbering");
    assert_eq!(
        n1.synthesized_text, "2.",
        "P1 synthesized text should be '2.'"
    );

    // For suff="nothing", rendered_text should contain NO tab or space
    // between the number and body text. It should be "1.No separator after number"
    let rt0 = p0
        .rendered_text
        .as_ref()
        .expect("P0 should have rendered_text");
    assert!(
        !rt0.starts_with("1.\t"),
        "suff='nothing': rendered_text should NOT have tab after '1.', got: {rt0:?}"
    );
    assert!(
        rt0.starts_with("1.No separator") || rt0.starts_with("1. No separator"),
        "suff='nothing': rendered_text should start with '1.No separator' (no tab/space), got: {rt0:?}"
    );
    // More specifically: it must be "1." immediately followed by body text, no gap
    assert!(
        rt0.starts_with("1.No separator"),
        "suff='nothing': expected '1.No separator...' with no separator char, got: {rt0:?}"
    );

    // Last two paragraphs use default suff (tab, numId=2)
    let p2 = paras[2];
    let n2 = p2.numbering.as_ref().expect("P2 should have numbering");
    assert_eq!(
        n2.synthesized_text, "1.",
        "P2 synthesized text should be '1.' (separate numId, fresh counter)"
    );

    let rt2 = p2
        .rendered_text
        .as_ref()
        .expect("P2 should have rendered_text");
    assert!(
        rt2.contains('\t'),
        "default suff (tab): rendered_text should contain a tab, got: {rt2:?}"
    );
}

// ── suff="space" (§17.9.28) ────────────────────────────────────────────

/// ISO 29500-1 §17.9.28: When suff val="space", a single space character
/// shall be placed between the numbering text and the paragraph body.
///
/// The rendered_text should be "1. Space after number" (space, not tab).
#[test]
fn spec_suff_space_uses_space_separator() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "suff-space");
    let paras = numbered_paragraphs(&doc);

    assert!(
        paras.len() >= 2,
        "expected at least 2 numbered paragraphs, got {}",
        paras.len()
    );

    let p0 = paras[0];
    let n0 = p0.numbering.as_ref().expect("P0 should have numbering");
    assert_eq!(
        n0.synthesized_text, "1.",
        "P0 synthesized text should be '1.'"
    );

    let rt0 = p0
        .rendered_text
        .as_ref()
        .expect("P0 should have rendered_text");

    // suff="space" means a single space between number and text
    assert!(
        !rt0.contains('\t'),
        "suff='space': rendered_text should NOT contain a tab, got: {rt0:?}"
    );
    assert!(
        rt0.starts_with("1. Space after number"),
        "suff='space': rendered_text should be '1. Space after number', got: {rt0:?}"
    );

    // Second paragraph
    let p1 = paras[1];
    let n1 = p1.numbering.as_ref().expect("P1 should have numbering");
    assert_eq!(
        n1.synthesized_text, "2.",
        "P1 synthesized text should be '2.'"
    );

    let rt1 = p1
        .rendered_text
        .as_ref()
        .expect("P1 should have rendered_text");
    assert!(
        rt1.starts_with("2. Second space item"),
        "suff='space': second rendered_text should be '2. Second space item', got: {rt1:?}"
    );
}

// ── pStyle reverse binding (§17.9.23) ──────────────────────────────────

/// ISO 29500-1 §17.9.23: When an abstract numbering level has
/// <w:pStyle w:val="ListNum"/>, any paragraph with style "ListNum" should
/// receive numbering from that level — even if the paragraph has no explicit
/// numPr and the style definition has no numPr.
///
/// The fixture has:
///   - abstractNum 0, level 0 with pStyle="ListNum"
///   - Style "ListNum" with NO numPr
///   - P0, P1: paragraphs with style "ListNum" (no numPr)
///   - P2: paragraph with explicit numPr (control)
///
/// P0 and P1 should get numbering via the reverse binding.
#[test]
fn spec_pstyle_reverse_binding_provides_numbering() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "pstyle-reverse-binding");
    let paras = all_paragraphs(&doc);

    // Find paragraphs with style "ListNum"
    let listnum_paras: Vec<&&stemma::ParagraphNode> = paras
        .iter()
        .filter(|p| p.style_id.as_deref() == Some("ListNum"))
        .collect();

    assert!(
        listnum_paras.len() >= 2,
        "expected at least 2 paragraphs with style 'ListNum', got {}. \
         Available styles: {:?}",
        listnum_paras.len(),
        paras
            .iter()
            .map(|p| p.style_id.as_deref())
            .collect::<Vec<_>>()
    );

    // P0: should have numbering via pStyle reverse binding
    let p0 = listnum_paras[0];
    let n0 = p0.numbering.as_ref();
    assert!(
        n0.is_some(),
        "P0 (style=ListNum, no numPr): should have numbering via pStyle reverse binding (§17.9.23), \
         but numbering is None. The reverse binding from abstractNum's pStyle='ListNum' should \
         provide numbering even without explicit numPr."
    );
    let n0 = n0.unwrap();
    assert_eq!(
        n0.synthesized_text, "1.",
        "P0 pStyle-bound numbering should synthesize '1.', got {:?}",
        n0.synthesized_text
    );

    // P1: should increment
    let p1 = listnum_paras[1];
    let n1 = p1.numbering.as_ref();
    assert!(
        n1.is_some(),
        "P1 (style=ListNum, no numPr): should have numbering via pStyle reverse binding"
    );
    let n1 = n1.unwrap();
    assert_eq!(
        n1.synthesized_text, "2.",
        "P1 pStyle-bound numbering should synthesize '2.', got {:?}",
        n1.synthesized_text
    );

    // P2: explicit numPr control — should also have numbering
    // P2 might also have ListNum style or might not. Let's check the third numbered paragraph.
    let all_numbered = numbered_paragraphs(&doc);
    assert!(
        all_numbered.len() >= 3,
        "expected at least 3 numbered paragraphs (2 via pStyle + 1 explicit), got {}",
        all_numbered.len()
    );
    let p2 = all_numbered[2];
    let n2 = p2.numbering.as_ref().unwrap();
    assert_eq!(
        n2.synthesized_text, "3.",
        "P2 (explicit numPr) should synthesize '3.', got {:?}",
        n2.synthesized_text
    );
}

// ── numStyleLink chain (§17.9.21 + §17.9.27) ──────────────────────────

/// ISO 29500-1 §17.9.21 + §17.9.27: An abstractNum with numStyleLink
/// references a numbering style, whose underlying abstractNum (with a
/// matching styleLink) provides the actual level definitions.
///
/// The fixture has:
///   abstractNum 0: numStyleLink="NumStyle" (no levels)
///   abstractNum 1: styleLink="NumStyle", levels: ilvl=0 upperRoman, ilvl=1 lowerLetter
///   numId=1 -> abstractNum 0
///   numId=2 -> abstractNum 1
///
/// Paragraphs use numId=1 — levels must be resolved via the chain.
#[test]
fn spec_numstylelink_resolves_via_chain() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "numstylelink-chain");
    let paras = numbered_paragraphs(&doc);

    assert!(
        paras.len() >= 3,
        "expected at least 3 numbered paragraphs, got {}. \
         If 0, the numStyleLink chain resolution likely failed entirely.",
        paras.len()
    );

    // P0: ilvl=0 via numStyleLink -> should use upperRoman from abstractNum 1
    let p0 = paras[0];
    let n0 = p0.numbering.as_ref().expect("P0 should have numbering");
    assert_eq!(
        n0.synthesized_text, "I.",
        "P0 (ilvl=0 via numStyleLink): should synthesize 'I.' (upperRoman), got {:?}. \
         The numStyleLink chain from abstractNum 0 -> styleLink on abstractNum 1 \
         should provide the upperRoman level definition.",
        n0.synthesized_text
    );

    // P1: ilvl=1 via numStyleLink -> should use lowerLetter from abstractNum 1
    let p1 = paras[1];
    let n1 = p1.numbering.as_ref().expect("P1 should have numbering");
    assert_eq!(
        n1.synthesized_text, "a)",
        "P1 (ilvl=1 via numStyleLink): should synthesize 'a)' (lowerLetter), got {:?}. \
         The numStyleLink chain should resolve ilvl=1 to abstractNum 1's level 1.",
        n1.synthesized_text
    );

    // P2: ilvl=0 again -> should increment to "II."
    let p2 = paras[2];
    let n2 = p2.numbering.as_ref().expect("P2 should have numbering");
    assert_eq!(
        n2.synthesized_text, "II.",
        "P2 (ilvl=0 via numStyleLink, second): should synthesize 'II.', got {:?}",
        n2.synthesized_text
    );
}

// ── startOverride=1 vs absent startOverride (§17.9.26) ─────────────────

/// ISO 29500-1 §17.9.26: startOverride resets the counter on first encounter.
/// Different numId instances that share the same abstractNum should have
/// INDEPENDENT counters — switching numId should start a fresh count.
///
/// The fixture has three num instances sharing abstractNum 0:
///   numId=1: no override — first batch (1., 2., 3.)
///   numId=2: startOverride=1 — second batch (should restart: 1., 2.)
///   numId=3: no override — third batch (fresh numId, should be 1., 2.)
#[test]
fn spec_start_override_resets_counter() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "start-override-vs-absent");
    let paras = numbered_paragraphs(&doc);

    assert!(
        paras.len() >= 7,
        "expected at least 7 numbered paragraphs, got {}",
        paras.len()
    );

    // First batch: numId=1, should be 1., 2., 3.
    let n0 = paras[0].numbering.as_ref().unwrap();
    let n1 = paras[1].numbering.as_ref().unwrap();
    let n2 = paras[2].numbering.as_ref().unwrap();
    assert_eq!(n0.synthesized_text, "1.", "batch 1, item 1");
    assert_eq!(n1.synthesized_text, "2.", "batch 1, item 2");
    assert_eq!(n2.synthesized_text, "3.", "batch 1, item 3");
    assert_eq!(n0.num_id, 1, "batch 1 should use numId=1");

    // Second batch: numId=2 with startOverride=1, should restart
    let n3 = paras[3].numbering.as_ref().unwrap();
    let n4 = paras[4].numbering.as_ref().unwrap();
    assert_eq!(
        n3.synthesized_text, "1.",
        "batch 2, item 1: startOverride=1 should restart to '1.', got {:?}",
        n3.synthesized_text
    );
    assert_eq!(
        n4.synthesized_text, "2.",
        "batch 2, item 2: should be '2.' after restart, got {:?}",
        n4.synthesized_text
    );
    assert_eq!(n3.num_id, 2, "batch 2 should use numId=2");

    // Third batch: numId=3 with NO override. Since this is a different numId,
    // it should have its own counter starting at 1.
    let n5 = paras[5].numbering.as_ref().unwrap();
    let n6 = paras[6].numbering.as_ref().unwrap();
    assert_eq!(
        n5.synthesized_text, "1.",
        "batch 3, item 1: numId=3 (no override, different numId) should start at '1.', got {:?}. \
         Different numId instances should have independent counters.",
        n5.synthesized_text
    );
    assert_eq!(
        n6.synthesized_text, "2.",
        "batch 3, item 2: should be '2.', got {:?}",
        n6.synthesized_text
    );
    assert_eq!(n5.num_id, 3, "batch 3 should use numId=3");
}

// ── start omitted, default=0 (§17.9.25) ────────────────────────────────

/// ISO 29500-1 §17.9.25: "If this element is omitted, then the starting
/// value shall be zero (0)."
///
/// When w:start is omitted on a decimal numbering level, the first item
/// should synthesize "0." (not "1."). This is the spec-mandated default.
///
/// The fixture has:
///   numId=1: start omitted (default=0) -> should produce 0., 1., 2.
///   numId=2: start=1 (explicit) -> should produce 1., 2., 3.
#[test]
fn spec_start_omitted_defaults_to_zero() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "start-omitted-default-zero");
    let paras = numbered_paragraphs(&doc);

    assert!(
        paras.len() >= 6,
        "expected at least 6 numbered paragraphs, got {}",
        paras.len()
    );

    // numId=1: start omitted (default=0 per §17.9.25)
    // First item should be "0.", second "1.", third "2."
    let n0 = paras[0].numbering.as_ref().unwrap();
    assert_eq!(n0.num_id, 1, "first batch should use numId=1");
    assert_eq!(
        n0.synthesized_text, "0.",
        "§17.9.25: start omitted defaults to 0. First item should be '0.', got {:?}. \
         The spec says 'If this element is omitted, then the starting value shall be zero (0).'",
        n0.synthesized_text
    );

    let n1 = paras[1].numbering.as_ref().unwrap();
    assert_eq!(
        n1.synthesized_text, "1.",
        "start-omitted second item should be '1.', got {:?}",
        n1.synthesized_text
    );

    let n2 = paras[2].numbering.as_ref().unwrap();
    assert_eq!(
        n2.synthesized_text, "2.",
        "start-omitted third item should be '2.', got {:?}",
        n2.synthesized_text
    );

    // numId=2: start=1 (control)
    let n3 = paras[3].numbering.as_ref().unwrap();
    assert_eq!(n3.num_id, 2, "second batch should use numId=2");
    assert_eq!(
        n3.synthesized_text, "1.",
        "start=1 first item should be '1.', got {:?}",
        n3.synthesized_text
    );

    let n4 = paras[4].numbering.as_ref().unwrap();
    assert_eq!(
        n4.synthesized_text, "2.",
        "start=1 second item should be '2.', got {:?}",
        n4.synthesized_text
    );

    let n5 = paras[5].numbering.as_ref().unwrap();
    assert_eq!(
        n5.synthesized_text, "3.",
        "start=1 third item should be '3.', got {:?}",
        n5.synthesized_text
    );
}

// ── numId counter resume after interleave (§17.9.15) ───────────────────

/// ISO 29500-1 §17.9.15: Each numbering definition instance (w:num) is
/// independent. When a document interleaves paragraphs using different numIds,
/// switching BACK to a previously-used numId should RESUME its counter, not
/// restart from the beginning.
///
/// The fixture interleaves: numId=1 (1.,2.), numId=2 ((a),(b)), numId=1 (3.,4.)
///
/// This tests that the counter state for numId=1 is preserved across the
/// numId=2 interleave.
#[test]
fn spec_numid_counter_resumes_after_interleave() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "numid-counter-resume");
    let paras = numbered_paragraphs(&doc);

    assert!(
        paras.len() >= 6,
        "expected at least 6 numbered paragraphs, got {}",
        paras.len()
    );

    // First batch: numId=1, decimal -> 1., 2.
    let n0 = paras[0].numbering.as_ref().unwrap();
    let n1 = paras[1].numbering.as_ref().unwrap();
    assert_eq!(n0.num_id, 1, "first batch should use numId=1");
    assert_eq!(n0.synthesized_text, "1.", "numId=1 first item");
    assert_eq!(n1.synthesized_text, "2.", "numId=1 second item");

    // Interleave: numId=2, lowerLetter -> (a), (b)
    let n2 = paras[2].numbering.as_ref().unwrap();
    let n3 = paras[3].numbering.as_ref().unwrap();
    assert_eq!(n2.num_id, 2, "interleave should use numId=2");
    assert_eq!(n2.synthesized_text, "(a)", "numId=2 first item");
    assert_eq!(n3.synthesized_text, "(b)", "numId=2 second item");

    // Resume: numId=1 should CONTINUE at 3., not restart at 1.
    let n4 = paras[4].numbering.as_ref().unwrap();
    let n5 = paras[5].numbering.as_ref().unwrap();
    assert_eq!(n4.num_id, 1, "resume should use numId=1");
    assert_eq!(
        n4.synthesized_text, "3.",
        "§17.9.15: After interleaving with numId=2, resuming numId=1 should continue \
         at '3.' (not restart at '1.'). Each num instance has independent counters \
         that persist across the document. Got {:?}",
        n4.synthesized_text
    );
    assert_eq!(
        n5.synthesized_text, "4.",
        "numId=1 fourth item should be '4.', got {:?}",
        n5.synthesized_text
    );
}
